import jwt
import json
from datetime import datetime
from typing import Dict, Any, Optional, List


def decode_and_verify_jwt(
    token: str,
    secret_key: str,
    algorithms: Optional[List[str]] = None,
    verify: bool = True,
    audience: Optional[str] = None,
    issuer: Optional[str] = None
) -> Dict[str, Any]:
    """
    Decode and verify JWT token securely.
    
    Args:
        token: JWT token string
        secret_key: Secret key for verification
        algorithms: List of allowed algorithms (defaults to ['HS256'])
        verify: Whether to verify signature (should always be True in production)
        audience: Expected audience claim
        issuer: Expected issuer claim
    
    Returns:
        Dictionary containing decoded token data and verification status
    """
    if algorithms is None:
        algorithms = ['HS256', 'HS384', 'HS512', 'RS256', 'RS384', 'RS512']
    
    # Prevent 'none' algorithm attack
    algorithms = [alg for alg in algorithms if alg.lower() != 'none']
    
    result = {
        'valid': False,
        'payload': None,
        'header': None,
        'errors': [],
        'warnings': []
    }
    
    # Decode header without verification to inspect algorithm
    try:
        header = jwt.get_unverified_header(token)
        result['header'] = header
        
        # Check for insecure algorithm
        if header.get('alg', '').lower() == 'none':
            result['errors'].append("CRITICAL: Token uses 'none' algorithm - INSECURE")
            return result
            
    except jwt.exceptions.DecodeError as e:
        result['errors'].append(f"Invalid token format: {str(e)}")
        return result
    
    # Verify and decode token
    try:
        options = {
            'verify_signature': verify,
            'verify_exp': verify,
            'verify_nbf': verify,
            'verify_iat': verify,
            'verify_aud': verify and audience is not None,
            'verify_iss': verify and issuer is not None
        }
        
        decode_kwargs = {
            'jwt': token,
            'key': secret_key,
            'algorithms': algorithms,
            'options': options
        }
        
        if audience:
            decode_kwargs['audience'] = audience
        if issuer:
            decode_kwargs['issuer'] = issuer
        
        payload = jwt.decode(**decode_kwargs)
        result['payload'] = payload
        result['valid'] = True
        
        # Add helpful debugging information
        if 'exp' in payload:
            exp_time = datetime.fromtimestamp(payload['exp'])
            result['expiration'] = exp_time.isoformat()
            if exp_time < datetime.now():
                result['warnings'].append(f"Token expired at {exp_time}")
        
        if 'iat' in payload:
            iat_time = datetime.fromtimestamp(payload['iat'])
            result['issued_at'] = iat_time.isoformat()
        
        if 'nbf' in payload:
            nbf_time = datetime.fromtimestamp(payload['nbf'])
            result['not_before'] = nbf_time.isoformat()
            if nbf_time > datetime.now():
                result['warnings'].append(f"Token not valid until {nbf_time}")
        
    except jwt.exceptions.ExpiredSignatureError:
        result['errors'].append("Token has expired")
        # Still decode without verification for debugging
        try:
            payload = jwt.decode(token, options={'verify_signature': False})
            result['payload'] = payload
        except:
            pass
            
    except jwt.exceptions.InvalidSignatureError:
        result['errors'].append("Invalid signature - token may be tampered with")
        
    except jwt.exceptions.InvalidAudienceError:
        result['errors'].append(f"Invalid audience. Expected: {audience}")
        
    except jwt.exceptions.InvalidIssuerError:
        result['errors'].append(f"Invalid issuer. Expected: {issuer}")
        
    except jwt.exceptions.ImmatureSignatureError:
        result['errors'].append("Token not yet valid (nbf claim)")
        
    except jwt.exceptions.DecodeError as e:
        result['errors'].append(f"Decode error: {str(e)}")
        
    except Exception as e:
        result['errors'].append(f"Unexpected error: {str(e)}")
    
    # Security warnings
    if not verify:
        result['warnings'].append("WARNING: Signature verification is disabled - use only for debugging!")
    
    return result


def print_jwt_debug_info(token: str, secret_key: str, **kwargs) -> None:
    """
    Print formatted JWT debug information.
    
    Args:
        token: JWT token string
        secret_key: Secret key for verification
        **kwargs: Additional arguments passed to decode_and_verify_jwt
    """
    result = decode_and_verify_jwt(token, secret_key, **kwargs)
    
    print("=" * 60)
    print("JWT TOKEN DEBUG INFORMATION")
    print("=" * 60)
    
    print(f"\nValid: {result['valid']}")
    
    if result['header']:
        print("\nHeader:")
        print(json.dumps(result['header'], indent=2))
    
    if result['payload']:
        print("\nPayload:")
        print(json.dumps(result['payload'], indent=2, default=str))
    
    if 'expiration' in result:
        print(f"\nExpiration: {result['expiration']}")
    if 'issued_at' in result:
        print(f"Issued At: {result['issued_at']}")
    if 'not_before' in result:
        print(f"Not Before: {result['not_before']}")
    
    if result['errors']:
        print("\nErrors:")
        for error in result['errors']:
            print(f"  - {error}")
    
    if result['warnings']:
        print("\nWarnings:")
        for warning in result['warnings']:
            print(f"  - {warning}")
    
    print("=" * 60)


